source:
plugins -> !@plugins

PluginInit -> { String:name }
PluginHook -> { String:event String:data }

register -> {
  String:plugin
  >- PluginInit{name -> plugin}
}

host -> {
  PluginInit -< e {
    -> plugins.registry.load{name -> e.name}!
  }
  PluginHook -< e {
    -> e.event ? {
      "start" -> plugins.registry.start{}!
      "stop" -> plugins.registry.stop{}!
      -> e.data
    }
  }
}
